INSERT INTO transfer_targets VALUES(10,'2026-summer','Modou Kéba Cissé','시세',1944705,'LASK → Aston Villa','CB','RCB','CONFIRMED','00200001420237413X9814X84',60.89999999999999858,31.19999999999999929,6,6.769999999999999574,'cb_defender','Balanced','cb_bpd','Aggressive',0.8900000000000000133,'CONFIRMED incoming: pre-contract signed summer 2025, joins for 2026/27 after a season at LASK. Measured: right-of-centre CB (60.9,31.2), Ball-Playing Defender/Aggressive fit 0.89 — same fit family as Konsa (0.88). Natural RCB cover/heir; Austrian Bundesliga level caveat. [2026-07-15 재확인] RotoWire: 공식 합류 확인(사전계약, LASK에서 2026년 여름 발효). [2026-07-15 3축+스탯 — 유지] 6경기: kp 0·xA .01·듀얼 3.8·태클 1.5·패스 84% — 진전 산출 없는 수비형, cb_defender/Balanced 처방 유지(움직임은 bpd/Aggressive .89로 콘사형 스텝아웃 — 기능축 우선). LASK 리그 수준 캐비앗.','https://readastonvilla.com/2026/05/14/modou-keba-cisse-the-future-aston-villa-player-who-is-shining-in-austria/ ; SofaScore API player 1944705 (2026-07-02)','CONFIRMED signing; measured from LASK (league-strength caveat). / 2026-07-15: 공식 완료 확인 — CONFIRMED 유지.','시세');
