INSERT INTO transfer_targets VALUES(18,'2026-summer','Anis Hadj Moussa','하지 무사',1218066,'Feyenoord','RW','RM','MEDIUM-HIGH','312691114X000140002400001',76.90000000000000569,69.29999999999999716,6,7.549999999999999823,'wm_insidefwd','Attack','wm_insidefwd','Attack',0.923000000000000042,'ADVANCE TALKS (Villa vs Newcastle); player prioritising a PL move for 26/27, Feyenoord ask ~€35m. Measured: high-and-wide right winger (76.9,69.3), Inside Forward/Attack fit 0.92 — the HIGHEST RM-slot fit sampled (Bowen 0.88) AND the highest avg rating of all targets (7.55). Eredivisie level caveat. [2026-07-03 watch: talks well underway with both Villa & Newcastle, expected to accelerate; Newcastle edge — Villa CL squad-registration restriction (UEFA fine) may hamper. Feyenoord ~€35m. Grade unchanged.] [2026-07-09 watch: TransferFeed/Yahoo — 빌라·뉴캐슬이 "most advanced in discussions" 공식 표현으로 보도, 선수 본인도 PL 선호 재확인. MEDIUM-HIGH에서 HIGH 상향.] [2026-07-15 재확인] Sacha Tavolieri(2티어급): "advanced talks" 보도 재확인, 대리인이 빌라·뉴캐슬 지목. 페예노르트 €35m 고수. [2026-07-15 3축+스탯 — 교정 winger/Attack→insidefwd/Attack] 6경기 스탯: xG .42·xA .46·kp 3.2·드리블 2.0·3골(평점 7.50 후보군 1위). 기능=득점+창조 양방 엘리트 = 컷인형 인사이드 포워드. 현커널 움직임도 insidefwd/Attack .923 최상 — 2축 일치로 교정. [2026-07-19 재검증] advanced talks 근거였던 Sky Sport Switzerland(Tavolieri)는 영국 Sky Sports 공식(tier-1)과 별개 매체로 재분류 — HIGH 유지 근거 약화. 선덜랜드 신규 문의·첼시 모니터링으로 경쟁 확대.','https://thehardtackle.com/transfer-news/2026/06/30/aston-villa-newcastle-united-advance-talks-to-sign-anis-hadj-moussa/ ; SofaScore API player 1218066 (2026-07-02)','MEDIUM-HIGH — Sky Sport Switzerland는 tier-1 아닌 별도 매체로 재분류, 2티어급 다수 관심 확인. [2026-07-19 재검증 하향]','하지무사');
INSERT INTO transfer_targets VALUES(30,'2026-summer','Tammy Abraham','타미 아브라함',610766,'Aston Villa','ST','ST','OWNED','01855255648X8415422010200',47.39999999999999858,59.0,4,6.849999999999999645,'st_target','Attack','st_false9','Attack',0.5210000000000000186,'ALREADY OWNED: 2026-01-27 베식타슈에서 ~£18m로 빌라 복귀(1일 만에 재이적), 그 시즌 유로파리그 우승. 여름 루머 대상이 아니라 보유 선수(알리송과 동일 케이스) — 사용자 요청으로 OWNED ST 옵션으로 편입. 실측(반시즌 통틀어 45분+ 4경기 전부 ST): 중앙-약간좌측·깊은 풋프린트 (47.4,59.0), 평균 6.85. 최근접 st_false9/Attack 0.52 — 왓킨스(st_advanced 자기커널)·기라시 0.80·브로베이 0.75·파르도 0.87보다 명확히 낮음. 처방은 타깃/홀드업 아키타입 반영 st_target/Attack. 표본 캐비앳: 왓킨스의 로테이션 백업이라 45분+ 경기가 반시즌 4경기뿐이고 전부 교체 출전(추격 상황 드롭) → 깊은 편향된 풋프린트, 선발 표본 아님. [2026-07-15 3축+스탯 — 유지] 6경기: xG .25·3골·kp 1.0·드리블 0 — 타깃형 피니셔, st_target/Attack(공중 플랜B, obs#19) 유지.','https://www.avfc.co.uk/news/2026/january/27/signing-aston-villa-confirm-tammy-abraham-signing/ ; SofaScore API player 610766 (2026-07-03)','OWNED — 이적 루머 아님(2026-01 합류확정 보유선수). 측정 신뢰 MEDIUM(표본 4경기·전부 교체출전·맥락 편향, 45분+ 6경기 미달).',NULL);
INSERT INTO transfer_targets VALUES(46,'2026-summer','Ibrahim Mbaye','이브라힘 음바예',1590918,'Paris Saint-Germain','FW','RM','MEDIUM-HIGH','001231104X000160001200000',75.79999999999999716,65.09999999999999431,243,6.919999999999999929,'wm_insidefwd','Balanced','wm_insidefwd','Balanced',0.958999999999999964,'측정 6경기(45분+, 2026-02-01~2026-07-01 확장표본 — PSG 로테이션/조커 자원이라 최근 30일 내 45분+ 경기가 부족해 리그1·챔피언스리그·월드컵·평가전으로 기간 확장, Fernández-Pardo 사례와 동일 방식): 우측 전진 배치(중심 tool_x=75.8, tool_y=65.1) — RM/RW 우측 인버티드 성향. 평균 평점 6.92. wm_insidefwd/Balanced 핏 0.959로 RM 슬롯 후보 중 최고 수준. 세계 최연소 월드컵 아프리카 득점자(vs 프랑스, 테오 에르난데스 제치고 득점)로 부각, PSG는 2028년까지 계약이라 매각 압박 없음. 빌라 £34m(€40m) 오퍼 준비설. [2026-07-15 재확인] TeamTalk: PSG 등 6개 클럽 컨택 확인, 빌라가 선두로 치고 나간 정황. "합의 임박" 보도는 저신뢰 소스발이라 유보적으로 반영. [2026-07-15 3축+스탯 — focus 교정 Attack→Balanced] 6경기 스탯: xG .27·xA .19·kp 1.2·드리블 1.3·패스 87%. 기능=득점·창조 균형(양방), 움직임도 insidefwd/Balanced .959 압도적 최상(Attack은 <.84) — Balanced가 정확. [2026-07-19 재검증] Romano(1티어) PSG 이탈 확정·멘드스 에이전트 선임 재확인, 다수 PL 클럽 경쟁 중 빌라 포함. 맨시티 하이잭 위협 신규 등장, 토트넘도 지속 경쟁 — 등급 유지. [2026-07-20 21시(4차) 재검증] TeamTalk(2티어): PSG가 오퍼에 열려있으며 빌라 포함 PL 6개 클럽 경쟁 — 경쟁 클럽 수 확대는 희석 신호. Romano발 신규 진전 없음. 등급 유지, 경쟁 심화를 리스크로 병기. [2026-07-21 예산 분석] €40-50m — 배정 범위 상한 부근이나 소화 가능. 유지.','https://api.sofascore.com/api/v1/player/1590918 (SofaScore API 실측, 2026-07-08) ; https://www.sportsmole.co.uk/football/aston-villa/transfer-talk/news/aston-villa-in-pole-position-for-psg-teenager-who-became-world-cup-history-maker_600822.html ; https://www.caughtoffside.com/2026/07/07/aston-villa-tottenham-circle-psg-wonderkid/ ; https://www.givemesport.com/aston-villa-frontrunners-sign-psg-ibrahim-mbaye/','MEDIUM-HIGH — 빌라 pole position/프론트러너, 협상 진전·선수 이적 희망(£40-50m). 구 UNKNOWN에서 상향(1티어급 다수 보도). 재검증 2026-07-10. / 2026-07-15 재확인: TeamTalk 6클럽 컨택 확인, 빌라 선두 정황(저신뢰 소스는 유보). [2026-07-19 재검증: 등급 유지, 맨시티 하이잭 리스크 신규]','음바예');
INSERT INTO transfer_targets VALUES(49,'2026-summer','Mandela Keita','케이타',1110136,'Parma','DM','LDM','MEDIUM-HIGH','1010025331387116X94121221',41.39999999999999858,42.70000000000000285,6,7.080000000000000071,'dm_holding','Ball-Winning','dm_dlp','Roaming',0.8599999999999999867,'오나나(LDM) ACL 부상 대체 후보 3인 중 하나(TeamTalk 단독). 파르마 이적료 €20-30m 요구, 스퍼스·아탈란타 등 경쟁. 실측: 좌측-중앙 딥 구역(tool_x 41.4, tool_y 42.7). dm_dlp/Roaming fit 0.80, avg rating 7.08(세리에A 6경기). [2026-07-15 재확인] 프론트러너 지위 유지(토트넘·브라이튼과 경쟁), 파르마는 공식 오퍼 시 매각 의향이나 아직 오퍼 없음. [2026-07-15 3축+스탯 — 유지] 6경기: kp 0·xA .01·듀얼 4.2·태클 1.8 — 순수 볼위너 확정, holding/Ball-Winning 유지. [2026-07-19 재검증] TeamTalk(2티어) 배경 조사만 확인, 7/14 기준 정식 접촉 없음 명시. 뉴캐슬(토날리 대체)·에버턴·아탈란타·토트넘까지 경쟁 급증. [2026-07-20 21시(4차) 재검증] TeamTalk(2티어): 오나나 ACL 부상 이후 케이타가 리즈·에버턴보다 앞서는 우선 타깃으로 격상 보도 — MEDIUM에서 MEDIUM-HIGH로 상향. 경쟁은 뉴캐슬·에버턴·아탈란타·토트넘까지 확대. [2026-07-21 예산 분석] €20-30m — 잔여 예산 내 소화 가능, 최신 보도상 중원 우선 타깃 격상과 정합. 유지.','https://www.footballfancast.com/aston-villa-now-transfer-frontrunners-mandela-keita-serie-a/ ; https://www.teamtalk.com/aston-villa/villa-target-lamine-camara-pape-gueye-mandela-keita-amadou-onana-injury-blow ; SofaScore API player 1110136 (2026-07-09)','MEDIUM — 2티어 관심 확인되나 리스트 검토 단계, 정식 접촉 없음. [2026-07-19 재검증 하향]','케이타');
INSERT INTO transfer_targets VALUES(75,'2026-summer','Pervis Estupiñán','에스투피냔',805465,'AC Milan','LB','LB','HIGH','21000X3100610007200032100',16.10000000000000143,49.10000000000000142,6,6.870000000000000106,'fb_att_wb','Support','fb_att_wb','Support',0.945999999999999953,'좌측면 전 깊이 커버 공격형 레프트백. 실측 6경기(세리에A, 322pt) 중심 tool(16,49). 커널 fit fb_att_wb/Support 0.946 (2위 fb_inverted/Build-Up 0.89). 밀란 아모림 구상 외, 호가 ~€14m. [2026-07-14 야간 재확인] Romano: "AVFC 좌측백 3인 숏리스트 중 상위, 딜 진행중, 협상 계속"(YouTube) — 단 조건 미확정, 데포르티보 라코루냐 경쟁 참전. 디뉴 대체가 아니라 마첸 백업/뎁스 역할로 영입(주전 보장 아님). [2026-07-15 재확인] Matteo Moretto(로마노 채널, 준1티어급): "협상 공식 개시" 확인 — 밀란-빌라 간 클럽 대 클럽 협상 단계 진입. 이적료 격차(€18-20m vs €10-12m)만 남음. 협상 단계 확인으로 HIGH 상향. [2026-07-15 3축+스탯 — 유지] 6경기: 패스 89%·태클 1.3·kp .8 — 견실 전진 LB. att_wb/Support 유지(마첸 07-15 교정 처방과 동일 — 경쟁 구도 명확). [2026-07-17 재확인] Romano(1티어): 개인조건 합의 완료. 클럽간 협상 advanced("non-stop contacts" — Longo), 이적료 격차 €12m vs €18-20m에서 Gazzetta €15m 절충설. 완료 임박 국면. [2026-07-18 재확인] 클럽간 최종 협상 단계 — 밀란 €18-20m vs 빌라 €10-12m에서 €15m 절충 근접(Gazzetta), "다음 주 초 이전 타결" 양측 낙관. 결정적 미팅 수일 내. [2026-07-19 재검증 강화] Romano(1티어, 7/16-17): 빌라가 에스투피냔과 개인조건 합의, 선수도 이적 희망, AC밀란과 이적료 협상 계속. 텔레그래프(2티어)도 advanced 확인. 이적료 격차만 남음(18-20m 밀란 요구 vs 10-13m대 빌라).','Moretto via SempreMilan https://sempremilan.com/moretto-aston-villa-enquire-milan-estupinan ; SofaScore player/805465 (6 Serie A ~2026-05-10)','HIGH — Romano(1티어) 개인조건 합의 확인, 이적료 협상 단계. [2026-07-19 재검증: 기존 HIGH 근거 강화] (2026-07-20 21시 재검증: 등급 유지. Moretto(1티어급)/GiveMeSport(Jacobs) — 개인조건 완전 타결 유지, 이적료만 €10-12m(빌라) vs €18-20m(밀란) 격차로 "one step away". 이번 주말 클럽간 회동으로 타결 시도 보도, 아직 미완료·공식발표 없음.)','에스투피냔');
INSERT INTO transfer_targets VALUES(76,'2026-summer','Antonio Nusa','누사',1121923,'RB Leipzig','LW','LM','MEDIUM-HIGH','13010X6210443002220010000',25.89999999999999858,58.70000000000000284,6,7.25,'wm_wideplm','Attack','wm_wideplm','Attack',0.8810000000000000053,'높고 넓은 좌측 윙어(하프스페이스 인사이드 드리프트). 실측 6경기(분데스리가, 257pt) 중심 tool(26,59). 커널 fit wm_wideplm/Attack 0.881 (2위 wm_insidefwd/Balanced 0.845). 라이프치히 호가 £43~50m, PL 5개팀 경쟁. MEDIUM-LOW에서 상향. [2026-07-15 재확인] Football Insider(2티어): 라이프치히 £50m면 매각 의향 확인, 뉴캐슬 등 경쟁 심화, 재정 부담 우려 지속. [2026-07-15 3축+스탯 — 유지] 6경기: 드리블 1.3·듀얼 4.7·xA .13·kp .8·2골·패스 71% — 기능은 직선 캐리어(플메형 창조 아님, 캐비앗). 움직임 wideplm/Attack .881 최상(insidefwd .845, Δ.036>.03) — 측정최적 유지. [2026-07-17 톱급 스탯 검증] 최근 6경기 xG .05·xA .13·kp .8·2골 + 직전 시즌 4골 3도움/31경기 — 벤치마크(로저스 시즌 xG .30·xA .20·kp 1.9) 대비 산출 전 지표 미달. £50m 밸류는 산출이 아니라 잠재력(21세·월드컵 임팩트) 프리미엄 — "톱 윙어" 후보로는 스탯 근거 부족, 로저스 직대체가 아닌 성장형 투자 프로필. [2026-07-19 재검증] tier-1/2 확인 소스 없음(3티어만: Football Insider원문은 confirm 안됨-재확인 필요, TheHardTackle/FootballFanCast). 라이프치히 매각 압박 없음(계약 2029), 뉴캐슬·아스날·스퍼스·팰리스 경쟁 지속. 등급 유지. [2026-07-20 21시(4차) 재검증] Football Insider(2티어) 복수 보도 — £50m 제안시 수락 가능·빌라뉴캐슬 추격 강화·오퍼 임박. 기존 3티어뿐이던 근거가 2티어로 보강됐으나 등급은 이미 MEDIUM-HIGH — 등급 유지, 근거만 보강. [2026-07-21 예산 분석] 라이프치히 요구 £50m — 잔여 예산 상한선(가능하나 단건 전액 소진). 유지.','Football Insider/TEAMtalk/ESPN 관심 보도; SofaScore player/1121923 (6 Bundesliga ~2026-05-16)','MEDIUM-HIGH — [2026-07-14 재확인] 라이프치히 호가 £50m(€50-60m)로 확정, 2029계약이라 "매각 압박 없음"(no immediate pressure to sell) 명시. 경쟁 7클럽으로 확대(뉴캐슬·아스날·토트넘·밀란·아틀레티코·크팰). 빌라 자체 재정 여건상 "£50m는 부담될 수 있다"는 반증 보도 등장 — 등급 MEDIUM-HIGH 유지하되 실현성 리스크 상향 병기. / 2026-07-15 재확인: Football Insider(2티어) £50m 매각 의향 확인, 재정 부담 우려 지속. [2026-07-19 재검증: 등급 유지]','누사');
